/**
 * Notification model types for the event-driven notification system.
 *
 * ARCHITECTURAL DECISION: All notifications flow through the EventBus.
 * Services emit domain events (e.g., order:created, user:updated) and the
 * NotificationService subscribes to these events, determines which notifications
 * to send, and dispatches them through the appropriate NotificationAdapter.
 *
 * This module defines the core types that all notification components depend on.
 * Adapters, services, and event handlers all reference these types.
 */

/**
 * Supported notification delivery channels.
 * Each channel has a corresponding adapter that implements NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'in_app' | 'webhook' | 'sms';

/**
 * Notification lifecycle status.
 * - pending: Created but not yet dispatched to an adapter
 * - sent: Successfully dispatched via the adapter
 * - failed: Adapter returned a failure (may be retried)
 */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * Notification priority levels.
 * Adapters may use priority to determine delivery urgency or retry behavior.
 */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';

/**
 * The payload that an adapter receives to deliver a notification.
 * This is the adapter-facing contract — every adapter receives this shape.
 */
export interface NotificationPayload {
  /** Unique notification ID (assigned by NotificationService) */
  id: string;
  /** Delivery channel this payload is intended for */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
  recipient: string;
  /** Notification subject/title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Priority level */
  priority: NotificationPriority;
  /** Additional metadata for adapter-specific behavior */
  metadata: Record<string, string>;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether the delivery attempt succeeded */
  success: boolean;
  /** Adapter-assigned external ID (e.g., email message ID) */
  externalId?: string;
  /** Error message if delivery failed */
  error?: string;
}

/**
 * A persisted notification record.
 * Stored by the NotificationService for tracking and querying.
 */
export interface Notification {
  /** Unique notification ID */
  id: string;
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier */
  recipient: string;
  /** Notification subject/title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Priority level */
  priority: NotificationPriority;
  /** Current delivery status */
  status: NotificationStatus;
  /** The domain event type that triggered this notification */
  triggeredBy: string;
  /** Additional metadata */
  metadata: Record<string, string>;
  /** When the notification was created */
  createdAt: Date;
  /** When the notification was last updated (e.g., status change) */
  updatedAt: Date;
}

/**
 * Input for creating a notification through the NotificationService.
 * Callers provide this; the service assigns ID, status, and timestamps.
 */
export interface CreateNotificationInput {
  /** Delivery channel */
  channel: NotificationChannel;
  /** Recipient identifier */
  recipient: string;
  /** Notification subject/title */
  subject: string;
  /** Notification body content */
  body: string;
  /** Priority level (defaults to 'normal' if omitted) */
  priority?: NotificationPriority;
  /** The domain event type that triggered this notification */
  triggeredBy: string;
  /** Additional metadata */
  metadata?: Record<string, string>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs email delivery attempts without
 * actually sending emails. It implements the full NotificationAdapter contract
 * so that the notification system can be wired up and tested end-to-end.
 *
 * To integrate a real email provider (e.g., SendGrid, SES, SMTP):
 * 1. Replace the stubbed send() logic with actual API/SMTP calls
 * 2. Inject provider credentials via constructor or config
 * 3. Map NotificationPayload fields to the provider's email format
 *
 * CONSTRAINT: This adapter must remain stateless — it receives a payload,
 * attempts delivery, and returns a result. No notification history is stored here.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender email address (the "from" field) */
  fromAddress: string;
  /** Optional sender display name */
  fromName?: string;
}

/**
 * Email notification adapter.
 * Implements NotificationAdapter for the 'email' channel.
 */
export class EmailAdapter implements NotificationAdapter {
  /** @inheritdoc */
  readonly channel = 'email' as const;

  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;

  constructor(config: EmailAdapterConfig) {
    this.config = config;
  }

  /**
   * Attempt to deliver a notification via email.
   *
   * Currently a stub that simulates successful delivery. In production,
   * this would call an email provider API (SendGrid, SES, SMTP, etc.).
   *
   * @param payload - The notification to deliver
   * @returns A result indicating success with a generated message ID
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(
      `Sending email to ${payload.recipient} from ${this.config.fromAddress}: "${payload.subject}"`,
    );

    // Validate recipient looks like an email address
    if (!this.isValidEmail(payload.recipient)) {
      this.logger.error(`Invalid email recipient: ${payload.recipient}`);
      return {
        success: false,
        error: `Invalid email address: ${payload.recipient}`,
      };
    }

    // Stub: simulate successful delivery
    // In production, this would be replaced with actual email sending logic:
    //   const response = await emailProvider.send({
    //     from: `${this.config.fromName} <${this.config.fromAddress}>`,
    //     to: payload.recipient,
    //     subject: payload.subject,
    //     body: payload.body,
    //   });
    const messageId = `email-${payload.id}-${Date.now()}`;

    this.logger.info(`Email delivered successfully: ${messageId}`);

    return {
      success: true,
      externalId: messageId,
    };
  }

  /**
   * Basic email format validation.
   */
  private isValidEmail(email: string): boolean {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  }
}

/**
 * Event type definitions for the event-driven system.
 *
 * ARCHITECTURAL CONSTRAINT: ALL inter-service communication MUST go through
 * the EventBus using these typed events. Services emit events when significant
 * actions occur, and interested listeners (including the NotificationService)
 * handle them independently.
 *
 * DO NOT use CallbackRegistry or direct service calls for cross-service
 * communication. The EventBus is the single mechanism for decoupled messaging.
 *
 * Adding a new event type:
 * 1. Define the event interface below with a unique `type` discriminator
 * 2. Add it to the AppEvent union type
 * 3. Emit it from the originating service via EventBus.emit()
 * 4. Subscribe in any interested service via EventBus.on()
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { Notification, NotificationChannel } from '../models/notification.js';

// ---------------------------------------------------------------------------
// Order domain events
// ---------------------------------------------------------------------------

export interface OrderCreatedEvent {
  type: 'order:created';
  order: Order;
  user: User;
  timestamp: Date;
}

export interface OrderStatusChangedEvent {
  type: 'order:status-changed';
  order: Order;
  previousStatus: string;
  newStatus: string;
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// User domain events
// ---------------------------------------------------------------------------

export interface UserCreatedEvent {
  type: 'user:created';
  user: User;
  timestamp: Date;
}

export interface UserUpdatedEvent {
  type: 'user:updated';
  user: User;
  changes: string[];
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// Notification domain events
// ---------------------------------------------------------------------------

/**
 * Emitted when a notification has been successfully sent via an adapter.
 * Useful for audit logging, analytics, or triggering follow-up actions.
 */
export interface NotificationSentEvent {
  type: 'notification:sent';
  notification: Notification;
  channel: NotificationChannel;
  externalId?: string;
  timestamp: Date;
}

/**
 * Emitted when a notification delivery attempt fails.
 * Listeners can use this for alerting, retry scheduling, or fallback logic.
 */
export interface NotificationFailedEvent {
  type: 'notification:failed';
  notification: Notification;
  channel: NotificationChannel;
  error: string;
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// Union type — all events in the system
// ---------------------------------------------------------------------------

export type AppEvent =
  | OrderCreatedEvent
  | OrderStatusChangedEvent
  | UserCreatedEvent
  | UserUpdatedEvent
  | NotificationSentEvent
  | NotificationFailedEvent;

export type EventType = AppEvent['type'];

