/**
 * Event type definitions for the event-driven system.
 *
 * ARCHITECTURAL CONSTRAINT: ALL inter-service communication MUST go through
 * the EventBus using these typed events. Services emit events when significant
 * actions occur, and interested listeners (including the NotificationService)
 * handle them independently.
 *
 * DO NOT use CallbackRegistry or direct service calls for cross-service
 * communication. The EventBus is the single mechanism for decoupled messaging.
 *
 * Adding a new event type:
 * 1. Define the event interface below with a unique `type` discriminator
 * 2. Add it to the AppEvent union type
 * 3. Emit it from the originating service via EventBus.emit()
 * 4. Subscribe in any interested service via EventBus.on()
 */

import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type { Notification, NotificationChannel } from '../models/notification.js';

// ---------------------------------------------------------------------------
// Order domain events
// ---------------------------------------------------------------------------

export interface OrderCreatedEvent {
  type: 'order:created';
  order: Order;
  user: User;
  timestamp: Date;
}

export interface OrderStatusChangedEvent {
  type: 'order:status-changed';
  order: Order;
  previousStatus: string;
  newStatus: string;
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// User domain events
// ---------------------------------------------------------------------------

export interface UserCreatedEvent {
  type: 'user:created';
  user: User;
  timestamp: Date;
}

export interface UserUpdatedEvent {
  type: 'user:updated';
  user: User;
  changes: string[];
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// Notification domain events
// ---------------------------------------------------------------------------

/**
 * Emitted when a notification has been successfully sent via an adapter.
 * Useful for audit logging, analytics, or triggering follow-up actions.
 */
export interface NotificationSentEvent {
  type: 'notification:sent';
  notification: Notification;
  channel: NotificationChannel;
  externalId?: string;
  timestamp: Date;
}

/**
 * Emitted when a notification delivery attempt fails.
 * Listeners can use this for alerting, retry scheduling, or fallback logic.
 */
export interface NotificationFailedEvent {
  type: 'notification:failed';
  notification: Notification;
  channel: NotificationChannel;
  error: string;
  timestamp: Date;
}

// ---------------------------------------------------------------------------
// Union type — all events in the system
// ---------------------------------------------------------------------------

export type AppEvent =
  | OrderCreatedEvent
  | OrderStatusChangedEvent
  | UserCreatedEvent
  | UserUpdatedEvent
  | NotificationSentEvent
  | NotificationFailedEvent;

export type EventType = AppEvent['type'];

/**
 * NotificationService — the central hub for event-driven notifications.
 *
 * ARCHITECTURE: Pure event-driven via EventBus.
 *
 * This service subscribes to domain events emitted by other services (e.g.,
 * order:created, order:status-changed, user:created) and translates them into
 * notifications dispatched through registered NotificationAdapters.
 *
 * Flow:
 * 1. A domain service (OrderService, UserService) emits an event via EventBus
 * 2. NotificationService receives the event via its EventBus subscriptions
 * 3. The event handler creates a notification record and determines the channel
 * 4. The notification is dispatched to the appropriate NotificationAdapter
 * 5. The adapter result updates the notification status
 * 6. A notification:sent or notification:failed event is emitted for audit
 *
 * CONSTRAINTS:
 * - ALL notification triggers come through EventBus subscriptions — no direct calls
 * - ALL adapters must implement the NotificationAdapter interface
 * - Adapters are registered at construction time and keyed by NotificationChannel
 * - The service owns notification state; adapters are stateless
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and emitting notification events
 * - NotificationAdapter implementations for actual delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  CreateNotificationInput,
  NotificationPayload,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

/**
 * Generate a sequential notification ID.
 */
function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/**
 * Reset the notification ID counter (for testing).
 */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter>;

  /**
   * Create a new NotificationService.
   *
   * @param eventBus - The EventBus to subscribe to for domain events
   * @param adapters - Map of channel to adapter implementation. Notifications
   *   targeting a channel without a registered adapter will be marked as failed.
   */
  constructor(
    private eventBus: EventBus,
    adapters?: Map<NotificationChannel, NotificationAdapter>,
  ) {
    this.adapters = adapters ?? new Map();
    this.registerEventHandlers();
  }

  // -----------------------------------------------------------------------
  // Event subscriptions — ALL notification triggers come through here
  // -----------------------------------------------------------------------

  /**
   * Register EventBus subscriptions for all domain events that trigger notifications.
   *
   * To add a new notification trigger:
   * 1. Define the event in event-types.ts
   * 2. Add a handler method below (e.g., handleSomeEvent)
   * 3. Subscribe to it here
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) => {
      return this.handleUserUpdated(event);
    });
  }

  // -----------------------------------------------------------------------
  // Event handlers — translate domain events into notifications
  // -----------------------------------------------------------------------

  /**
   * Handle order:created — send order confirmation to the customer.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Handling order:created for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
      triggeredBy: 'order:created',
      metadata: {
        orderId: event.order.id,
        userId: event.user.id,
      },
    });
  }

  /**
   * Handle order:status-changed — notify the customer of the status update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Handling order:status-changed for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const priority = event.newStatus === 'cancelled' ? 'high' : 'normal';

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority,
      triggeredBy: 'order:status-changed',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Handle user:created — send a welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Handling user:created for user ${event.user.id}`);

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro! Your account has been created.`,
      priority: 'normal',
      triggeredBy: 'user:created',
      metadata: {
        userId: event.user.id,
      },
    });
  }

  /**
   * Handle user:updated — notify the user of account changes.
   */
  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    this.logger.info(`Handling user:updated for user ${event.user.id}`);

    const changesDescription = event.changes.join(', ');

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${changesDescription}.`,
      priority: 'normal',
      triggeredBy: 'user:updated',
      metadata: {
        userId: event.user.id,
        changes: event.changes.join(','),
      },
    });
  }

  // -----------------------------------------------------------------------
  // Core notification dispatch logic
  // -----------------------------------------------------------------------

  /**
   * Create a notification record and dispatch it through the appropriate adapter.
   *
   * This is the central method that all event handlers call. It:
   * 1. Creates and stores the notification record
   * 2. Looks up the adapter for the notification's channel
   * 3. Dispatches via the adapter
   * 4. Updates the notification status based on the result
   * 5. Emits a notification:sent or notification:failed event
   *
   * @param input - The notification creation input
   * @returns The created notification record
   */
  async createAndDispatch(input: CreateNotificationInput): Promise<Notification> {
    const notification = this.createNotificationRecord(input);
    this.notifications.push(notification);

    const adapter = this.adapters.get(input.channel);

    if (!adapter) {
      // No adapter registered for this channel — log but don't fail hard.
      // The notification is stored with 'pending' status; an adapter can be
      // registered later and pending notifications can be retried.
      this.logger.warn(
        `No adapter registered for channel '${input.channel}'. ` +
        `Notification ${notification.id} stored as pending.`,
      );
      return notification;
    }

    const payload = this.toPayload(notification);

    try {
      const result = await adapter.send(payload);

      if (result.success) {
        notification.status = 'sent';
        notification.updatedAt = new Date();

        await this.eventBus.emit({
          type: 'notification:sent',
          notification,
          channel: notification.channel,
          externalId: result.externalId,
          timestamp: new Date(),
        });

        this.logger.info(`Notification ${notification.id} sent successfully via ${input.channel}`);
      } else {
        notification.status = 'failed';
        notification.updatedAt = new Date();

        await this.eventBus.emit({
          type: 'notification:failed',
          notification,
          channel: notification.channel,
          error: result.error ?? 'Unknown error',
          timestamp: new Date(),
        });

        this.logger.error(
          `Notification ${notification.id} failed via ${input.channel}: ${result.error}`,
        );
      }
    } catch (err) {
      notification.status = 'failed';
      notification.updatedAt = new Date();

      const errorMessage = err instanceof Error ? err.message : 'Unknown error';

      await this.eventBus.emit({
        type: 'notification:failed',
        notification,
        channel: notification.channel,
        error: errorMessage,
        timestamp: new Date(),
      });

      this.logger.error(
        `Notification ${notification.id} threw during dispatch: ${errorMessage}`,
      );
    }

    return notification;
  }

  // -----------------------------------------------------------------------
  // Query methods
  // -----------------------------------------------------------------------

  /**
   * Get all stored notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications by status.
   */
  getNotificationsByStatus(status: Notification['status']): Notification[] {
    return this.notifications.filter((n) => n.status === status);
  }

  /**
   * Get notifications by channel.
   */
  getNotificationsByChannel(channel: NotificationChannel): Notification[] {
    return this.notifications.filter((n) => n.channel === channel);
  }

  /**
   * Get the count of stored notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all stored notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }

  // -----------------------------------------------------------------------
  // Adapter management
  // -----------------------------------------------------------------------

  /**
   * Register a notification adapter for a channel.
   * Overwrites any previously registered adapter for that channel.
   *
   * @param adapter - The adapter to register
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Check if an adapter is registered for a given channel.
   */
  hasAdapter(channel: NotificationChannel): boolean {
    return this.adapters.has(channel);
  }

  // -----------------------------------------------------------------------
  // Private helpers
  // -----------------------------------------------------------------------

  /**
   * Create a notification record from input.
   */
  private createNotificationRecord(input: CreateNotificationInput): Notification {
    const now = new Date();
    return {
      id: generateNotificationId(),
      channel: input.channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      priority: input.priority ?? 'normal',
      status: 'pending',
      triggeredBy: input.triggeredBy,
      metadata: input.metadata ?? {},
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Convert a notification record to an adapter payload.
   */
  private toPayload(notification: Notification): NotificationPayload {
    return {
      id: notification.id,
      channel: notification.channel,
      recipient: notification.recipient,
      subject: notification.subject,
      body: notification.body,
      priority: notification.priority,
      metadata: notification.metadata,
    };
  }
}

/**
 * NotificationService — the central hub for event-driven notifications.
 *
 * ARCHITECTURE: Pure event-driven via EventBus.
 *
 * This service subscribes to domain events emitted by other services (e.g.,
 * order:created, order:status-changed, user:created) and translates them into
 * notifications dispatched through registered NotificationAdapters.
 *
 * Flow:
 * 1. A domain service (OrderService, UserService) emits an event via EventBus
 * 2. NotificationService receives the event via its EventBus subscriptions
 * 3. The event handler creates a notification record and determines the channel
 * 4. The notification is dispatched to the appropriate NotificationAdapter
 * 5. The adapter result updates the notification status
 * 6. A notification:sent or notification:failed event is emitted for audit
 *
 * CONSTRAINTS:
 * - ALL notification triggers come through EventBus subscriptions — no direct calls
 * - ALL adapters must implement the NotificationAdapter interface
 * - Adapters are registered at construction time and keyed by NotificationChannel
 * - The service owns notification state; adapters are stateless
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events and emitting notification events
 * - NotificationAdapter implementations for actual delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationChannel,
  CreateNotificationInput,
  NotificationPayload,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

/**
 * Generate a sequential notification ID.
 */
function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/**
 * Reset the notification ID counter (for testing).
 */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationChannel, NotificationAdapter>;

  /**
   * Create a new NotificationService.
   *
   * @param eventBus - The EventBus to subscribe to for domain events
   * @param adapters - Map of channel to adapter implementation. Notifications
   *   targeting a channel without a registered adapter will be stored as pending.
   */
  constructor(
    private eventBus: EventBus,
    adapters?: Map<NotificationChannel, NotificationAdapter>,
  ) {
    this.adapters = adapters ?? new Map();
    this.registerEventHandlers();
  }

  // -----------------------------------------------------------------------
  // Event subscriptions — ALL notification triggers come through here
  // -----------------------------------------------------------------------

  /**
   * Register EventBus subscriptions for all domain events that trigger notifications.
   *
   * To add a new notification trigger:
   * 1. Define the event in event-types.ts
   * 2. Add a handler method below (e.g., handleSomeEvent)
   * 3. Subscribe to it here
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) => {
      return this.handleUserUpdated(event);
    });
  }

  // -----------------------------------------------------------------------
  // Event handlers — translate domain events into notifications
  // -----------------------------------------------------------------------

  /**
   * Handle order:created — send order confirmation to the customer.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Handling order:created for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      priority: 'normal',
      triggeredBy: 'order:created',
      metadata: {
        orderId: event.order.id,
        userId: event.user.id,
      },
    });
  }

  /**
   * Handle order:status-changed — notify the customer of the status update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Handling order:status-changed for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const priority = event.newStatus === 'cancelled' ? 'high' : 'normal';

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      priority,
      triggeredBy: 'order:status-changed',
      metadata: {
        orderId: event.order.id,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Handle user:created — send a welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    this.logger.info(`Handling user:created for user ${event.user.id}`);

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro! Your account has been created.`,
      priority: 'normal',
      triggeredBy: 'user:created',
      metadata: {
        userId: event.user.id,
      },
    });
  }

  /**
   * Handle user:updated — notify the user of account changes.
   */
  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    this.logger.info(`Handling user:updated for user ${event.user.id}`);

    const changesDescription = event.changes.join(', ');

    await this.createAndDispatch({
      channel: 'email',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${changesDescription}.`,
      priority: 'normal',
      triggeredBy: 'user:updated',
      metadata: {
        userId: event.user.id,
        changes: event.changes.join(','),
      },
    });
  }

  // -----------------------------------------------------------------------
  // Core notification dispatch logic
  // -----------------------------------------------------------------------

  /**
   * Create a notification record and dispatch it through the appropriate adapter.
   *
   * This is the central method that all event handlers call. It:
   * 1. Creates and stores the notification record
   * 2. Looks up the adapter for the notification's channel
   * 3. Dispatches via the adapter
   * 4. Updates the notification status based on the result
   * 5. Emits a notification:sent or notification:failed event
   *
   * @param input - The notification creation input
   * @returns The created notification record
   */
  async createAndDispatch(input: CreateNotificationInput): Promise<Notification> {
    const notification = this.createNotificationRecord(input);
    this.notifications.push(notification);

    const adapter = this.adapters.get(input.channel);

    if (!adapter) {
      // No adapter registered for this channel — log but don't fail hard.
      // The notification is stored with 'pending' status; an adapter can be
      // registered later and pending notifications can be retried.
      this.logger.warn(
        `No adapter registered for channel '${input.channel}'. ` +
        `Notification ${notification.id} stored as pending.`,
      );
      return notification;
    }

    const payload = this.toPayload(notification);

    try {
      const result = await adapter.send(payload);

      if (result.success) {
        notification.status = 'sent';
        notification.updatedAt = new Date();

        await this.eventBus.emit({
          type: 'notification:sent',
          notification,
          channel: notification.channel,
          externalId: result.externalId,
          timestamp: new Date(),
        });

        this.logger.info(`Notification ${notification.id} sent successfully via ${input.channel}`);
      } else {
        notification.status = 'failed';
        notification.updatedAt = new Date();

        await this.eventBus.emit({
          type: 'notification:failed',
          notification,
          channel: notification.channel,
          error: result.error ?? 'Unknown error',
          timestamp: new Date(),
        });

        this.logger.error(
          `Notification ${notification.id} failed via ${input.channel}: ${result.error}`,
        );
      }
    } catch (err) {
      notification.status = 'failed';
      notification.updatedAt = new Date();

      const errorMessage = err instanceof Error ? err.message : 'Unknown error';

      await this.eventBus.emit({
        type: 'notification:failed',
        notification,
        channel: notification.channel,
        error: errorMessage,
        timestamp: new Date(),
      });

      this.logger.error(
        `Notification ${notification.id} threw during dispatch: ${errorMessage}`,
      );
    }

    return notification;
  }

  // -----------------------------------------------------------------------
  // Query methods
  // -----------------------------------------------------------------------

  /**
   * Get all stored notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications by status.
   */
  getNotificationsByStatus(status: Notification['status']): Notification[] {
    return this.notifications.filter((n) => n.status === status);
  }

  /**
   * Get notifications by channel.
   */
  getNotificationsByChannel(channel: NotificationChannel): Notification[] {
    return this.notifications.filter((n) => n.channel === channel);
  }

  /**
   * Get the count of stored notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all stored notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }

  // -----------------------------------------------------------------------
  // Adapter management
  // -----------------------------------------------------------------------

  /**
   * Register a notification adapter for a channel.
   * Overwrites any previously registered adapter for that channel.
   *
   * @param adapter - The adapter to register
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Check if an adapter is registered for a given channel.
   */
  hasAdapter(channel: NotificationChannel): boolean {
    return this.adapters.has(channel);
  }

  // -----------------------------------------------------------------------
  // Private helpers
  // -----------------------------------------------------------------------

  /**
   * Create a notification record from input.
   */
  private createNotificationRecord(input: CreateNotificationInput): Notification {
    const now = new Date();
    return {
      id: generateNotificationId(),
      channel: input.channel,
      recipient: input.recipient,
      subject: input.subject,
      body: input.body,
      priority: input.priority ?? 'normal',
      status: 'pending',
      triggeredBy: input.triggeredBy,
      metadata: input.metadata ?? {},
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Convert a notification record to an adapter payload.
   */
  private toPayload(notification: Notification): NotificationPayload {
    return {
      id: notification.id,
      channel: notification.channel,
      recipient: notification.recipient,
      subject: notification.subject,
      body: notification.body,
      priority: notification.priority,
      metadata: notification.metadata,
    };
  }
}

