parameters.content:
/**
 * TaskFlow Pro — A task and order management system.
 *
 * Architecture:
 * - Service Layer: UserService, OrderService, NotificationService (business logic)
 * - Repository Layer: UserRepository, OrderRepository (data access via Repository pattern)
 * - Adapter Layer: EmailAdapter (notification delivery via NotificationAdapter interface)
 * - Utility Layer: Database, Logger, Pagination (infrastructure)
 * - Event System: EventBus with typed events (decoupled communication)
 *
 * Key architectural decisions:
 * 1. Repository pattern for all data access (no direct DB calls from services)
 * 2. Event-driven notifications — ALL inter-service communication via EventBus
 * 3. Adapter pattern for notification delivery — all adapters implement NotificationAdapter
 */

// Models
export type { User, CreateUserInput, UpdateUserInput } from './models/user.js';
export type {
  Order,
  OrderItem,
  OrderStatus,
  CreateOrderInput,
} from './models/order.js';
export { calculateOrderTotal } from './models/order.js';
export type {
  Notification,
  NotificationChannel,
  NotificationStatus,
  NotificationPriority,
  NotificationPayload,
  NotificationResult,
  CreateNotificationInput,
} from './models/notification.js';

// Utilities
export { Database, getDatabase, resetDatabase } from './utils/database.js';
export { Logger } from './utils/logger.js';
export { paginate } from './utils/pagination.js';
export type { PaginationResult } from './utils/pagination.js';

// Repositories
export { BaseRepository } from './repositories/base.repository.js';
export { UserRepository } from './repositories/user.repository.js';
export { OrderRepository } from './repositories/order.repository.js';

// Events
export { EventBus } from './events/event-bus.js';
export type {
  AppEvent,
  EventType,
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
  NotificationSentEvent,
  NotificationFailedEvent,
} from './events/event-types.js';

// Services
export { UserService } from './services/user.service.js';
export { OrderService } from './services/order.service.js';
export { NotificationService } from './services/notification.service.js';

// Adapters
export type { NotificationAdapter } from './adapters/notification.adapter.js';
export { EmailAdapter } from './adapters/email.adapter.js';
export type { EmailAdapterConfig } from './adapters/email.adapter.js';

// Config
export { createConfig, defaultConfig } from './config/app.config.js';
export type { AppConfig } from './config/app.config.js';

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationAdapter } from '../../src/adapters/notification.adapter.js';
import type { NotificationPayload, NotificationResult, NotificationChannel } from '../../src/models/notification.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  UserCreatedEvent,
  UserUpdatedEvent,
} from '../../src/events/event-types.js';

/**
 * Helper: create a stub adapter that always succeeds.
 */
function createSuccessAdapter(channel: NotificationChannel): NotificationAdapter {
  return {
    channel,
    send: async (payload: NotificationPayload): Promise<NotificationResult> => ({
      success: true,
      externalId: `ext-${payload.id}`,
    }),
  };
}

/**
 * Helper: create a stub adapter that always fails.
 */
function createFailureAdapter(channel: NotificationChannel, error: string): NotificationAdapter {
  return {
    channel,
    send: async (): Promise<NotificationResult> => ({
      success: false,
      error,
    }),
  };
}

/**
 * Helper: create a stub adapter that throws.
 */
function createThrowingAdapter(channel: NotificationChannel, error: string): NotificationAdapter {
  return {
    channel,
    send: async (): Promise<NotificationResult> => {
      throw new Error(error);
    },
  };
}

describe('NotificationService', () => {
  let eventBus: EventBus;
  let service: NotificationService;
  let emailAdapter: NotificationAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    emailAdapter = createSuccessAdapter('email');
    const adapters = new Map<NotificationChannel, NotificationAdapter>();
    adapters.set('email', emailAdapter);
    service = new NotificationService(eventBus, adapters);
    resetNotificationIdCounter();
  });

  // -----------------------------------------------------------------------
  // order:created handler
  // -----------------------------------------------------------------------

  describe('order:created handler', () => {
    it('should send notification on order created', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.subject).toContain('Order Confirmation');
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('$20.00');
      expect(notifications[0]?.status).toBe('sent');
      expect(notifications[0]?.channel).toBe('email');
      expect(notifications[0]?.triggeredBy).toBe('order:created');
    });

    it('should include all items in notification body', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
            { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
          ],
          total: 45,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.body).toContain('Widget x2');
      expect(notifications[0]?.body).toContain('Gadget x1');
    });

    it('should include order metadata', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-42',
          userId: 'user-7',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-7',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.metadata).toEqual({
        orderId: 'order-42',
        userId: 'user-7',
      });
    });
  });

  // -----------------------------------------------------------------------
  // order:status-changed handler (now via EventBus, not CallbackRegistry)
  // -----------------------------------------------------------------------

  describe('order:status-changed handler', () => {
    it('should send notification on status change via EventBus', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Order Update');
      expect(notifications[0]?.body).toContain('pending');
      expect(notifications[0]?.body).toContain('confirmed');
      expect(notifications[0]?.status).toBe('sent');
    });

    it('should set high priority for cancelled orders', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.priority).toBe('high');
    });
  });

  // -----------------------------------------------------------------------
  // user:created handler
  // -----------------------------------------------------------------------

  describe('user:created handler', () => {
    it('should send welcome notification on user created', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Welcome');
      expect(notifications[0]?.body).toContain('Alice');
      expect(notifications[0]?.recipient).toBe('alice@example.com');
      expect(notifications[0]?.triggeredBy).toBe('user:created');
    });
  });

  // -----------------------------------------------------------------------
  // user:updated handler
  // -----------------------------------------------------------------------

  describe('user:updated handler', () => {
    it('should send update notification on user updated', async () => {
      const event: UserUpdatedEvent = {
        type: 'user:updated',
        user: {
          id: 'user-1',
          name: 'Alice Smith',
          email: 'alice@example.com',
          role: 'admin',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        changes: ['name', 'role'],
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]?.subject).toContain('Account Updated');
      expect(notifications[0]?.body).toContain('name, role');
      expect(notifications[0]?.triggeredBy).toBe('user:updated');
    });
  });

  // -----------------------------------------------------------------------
  // Adapter dispatch
  // -----------------------------------------------------------------------

  describe('adapter dispatch', () => {
    it('should mark notification as sent when adapter succeeds', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const notifications = service.getNotifications();
      expect(notifications[0]?.status).toBe('sent');
    });

    it('should mark notification as failed when adapter returns failure', async () => {
      const failBus = new EventBus();
      const failAdapter = createFailureAdapter('email', 'SMTP connection refused');
      const adapters = new Map<NotificationChannel, NotificationAdapter>();
      adapters.set('email', failAdapter);
      const failService = new NotificationService(failBus, adapters);
      resetNotificationIdCounter();

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await failBus.emit(event);

      const notifications = failService.getNotifications();
      expect(notifications[0]?.status).toBe('failed');
    });

    it('should mark notification as failed when adapter throws', async () => {
      const throwBus = new EventBus();
      const throwAdapter = createThrowingAdapter('email', 'Connection timeout');
      const adapters = new Map<NotificationChannel, NotificationAdapter>();
      adapters.set('email', throwAdapter);
      const throwService = new NotificationService(throwBus, adapters);
      resetNotificationIdCounter();

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await throwBus.emit(event);

      const notifications = throwService.getNotifications();
      expect(notifications[0]?.status).toBe('failed');
    });

    it('should store notification as pending when no adapter registered', async () => {
      const noAdapterBus = new EventBus();
      const noAdapterService = new NotificationService(noAdapterBus);
      resetNotificationIdCounter();

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
