+/**
+ * Email notification adapter — delivers notifications via email.
+ *
+ * This is a stub implementation that logs email delivery attempts without
+ * actually sending emails. It implements the full NotificationAdapter contract
+ * so that the notification system can be wired up and tested end-to-end.
+ *
+ * To integrate a real email provider (e.g., SendGrid, SES, SMTP):
+ * 1. Replace the stubbed send() logic with actual API/SMTP calls
+ * 2. Inject provider credentials via constructor or config
+ * 3. Map NotificationPayload fields to the provider's email format
+ *
+ * CONSTRAINT: This adapter must remain stateless — it receives a payload,
+ * attempts delivery, and returns a result. No notification history is stored here.
+ */
+
+import type { NotificationAdapter } from './notification.adapter.js';
+import type { NotificationPayload, NotificationResult } from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * Configuration for the email adapter.
+ */
+export interface EmailAdapterConfig {
+  /** Sender email address (the "from" field) */
+  fromAddress: string;
+  /** Optional sender display name */
+  fromName?: string;
+}
+
+/**
+ * Email notification adapter.
+ * Implements NotificationAdapter for the 'email' channel.
+ */
+export class EmailAdapter implements NotificationAdapter {
+  /** @inheritdoc */
+  readonly channel = 'email' as const;
+
+  private logger = new Logger('EmailAdapter');
+  private config: EmailAdapterConfig;
+
+  constructor(config: EmailAdapterConfig) {
+    this.config = config;
+  }
+
+  /**
+   * Attempt to deliver a notification via email.
+   *
+   * Currently a stub that simulates successful delivery. In production,
+   * this would call an email provider API (SendGrid, SES, SMTP, etc.).
+   *
+   * @param payload - The notification to deliver
+   * @returns A result indicating success with a generated message ID
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    this.logger.info(
+      `Sending email to ${payload.recipient} from ${this.config.fromAddress}: "${payload.subject}"`,
+    );
+
+    // Validate recipient looks like an email address
+    if (!this.isValidEmail(payload.recipient)) {
+      this.logger.error(`Invalid email recipient: ${payload.recipient}`);
+      return {
+        success: false,
+        error: `Invalid email address: ${payload.recipient}`,
+      };
+    }
+
+    // Stub: simulate successful delivery
+    // In production, this would be replaced with actual email sending logic:
+    //   const response = await emailProvider.send({
+    //     from: `${this.config.fromName} <${this.config.fromAddress}>`,
+    //     to: payload.recipient,
+    //     subject: payload.subject,
+    //     body: payload.body,
+    //   });
+    const messageId = `email-${payload.id}-${Date.now()}`;
+
+    this.logger.info(`Email delivered successfully: ${messageId}`);
+
+    return {
+      success: true,
+      externalId: messageId,
+    };
+  }
+
+  /**
+   * Basic email format validation.
+   */
+  private isValidEmail(email: string): boolean {
+    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
+  }
+}

