+/**
+ * Notification model types for the event-driven notification system.
+ *
+ * ARCHITECTURAL DECISION: All notifications flow through the EventBus.
+ * Services emit domain events (e.g., order:created, user:updated) and the
+ * NotificationService subscribes to these events, determines which notifications
+ * to send, and dispatches them through the appropriate NotificationAdapter.
+ *
+ * This module defines the core types that all notification components depend on.
+ * Adapters, services, and event handlers all reference these types.
+ */
+
+/**
+ * Supported notification delivery channels.
+ * Each channel has a corresponding adapter that implements NotificationAdapter.
+ */
+export type NotificationChannel = 'email' | 'in_app' | 'webhook' | 'sms';
+
+/**
+ * Notification lifecycle status.
+ * - pending: Created but not yet dispatched to an adapter
+ * - sent: Successfully dispatched via the adapter
+ * - failed: Adapter returned a failure (may be retried)
+ */
+export type NotificationStatus = 'pending' | 'sent' | 'failed';
+
+/**
+ * Notification priority levels.
+ * Adapters may use priority to determine delivery urgency or retry behavior.
+ */
+export type NotificationPriority = 'low' | 'normal' | 'high' | 'urgent';
+
+/**
+ * The payload that an adapter receives to deliver a notification.
+ * This is the adapter-facing contract — every adapter receives this shape.
+ */
+export interface NotificationPayload {
+  /** Unique notification ID (assigned by NotificationService) */
+  id: string;
+  /** Delivery channel this payload is intended for */
+  channel: NotificationChannel;
+  /** Recipient identifier (email address, user ID, webhook URL, etc.) */
+  recipient: string;
+  /** Notification subject/title */
+  subject: string;
+  /** Notification body content */
+  body: string;
+  /** Priority level */
+  priority: NotificationPriority;
+  /** Additional metadata for adapter-specific behavior */
+  metadata: Record<string, string>;
+}
+
+/**
+ * Result returned by a NotificationAdapter after attempting delivery.
+ */
+export interface NotificationResult {
+  /** Whether the delivery attempt succeeded */
+  success: boolean;
+  /** Adapter-assigned external ID (e.g., email message ID) */
+  externalId?: string;
+  /** Error message if delivery failed */
+  error?: string;
+}
+
+/**
+ * A persisted notification record.
+ * Stored by the NotificationService for tracking and querying.
+ */
+export interface Notification {
+  /** Unique notification ID */
+  id: string;
+  /** Delivery channel */
+  channel: NotificationChannel;
+  /** Recipient identifier */
+  recipient: string;
+  /** Notification subject/title */
+  subject: string;
+  /** Notification body content */
+  body: string;
+  /** Priority level */
+  priority: NotificationPriority;
+  /** Current delivery status */
+  status: NotificationStatus;
+  /** The domain event type that triggered this notification */
+  triggeredBy: string;
+  /** Additional metadata */
+  metadata: Record<string, string>;
+  /** When the notification was created */
+  createdAt: Date;
+  /** When the notification was last updated (e.g., status change) */
+  updatedAt: Date;
+}
+
+/**
+ * Input for creating a notification through the NotificationService.
+ * Callers provide this; the service assigns ID, status, and timestamps.
+ */
+export interface CreateNotificationInput {
+  /** Delivery channel */
+  channel: NotificationChannel;
+  /** Recipient identifier */
+  recipient: string;
+  /** Notification subject/title */
+  subject: string;
+  /** Notification body content */
+  body: string;
+  /** Priority level (defaults to 'normal' if omitted) */
+  priority?: NotificationPriority;
+  /** The domain event type that triggered this notification */
+  triggeredBy: string;
+  /** Additional metadata */
+  metadata?: Record<string, string>;
+}

