@@ -0,0 +1,63 @@
+import { describe, it, expect, beforeEach } from 'vitest';
+import { EmailAdapter } from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+describe('EmailAdapter', () => {
+  let adapter: EmailAdapter;
+
+  beforeEach(() => {
+    adapter = new EmailAdapter({
+      fromAddress: 'noreply@taskflow.com',
+      fromName: 'TaskFlow Pro',
+    });
+  });
+
+  /**
+   * Helper: create a valid email notification payload.
+   */
+  function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
+    return {
+      id: 'notif-0001',
+      channel: 'email',
+      recipient: 'alice@example.com',
+      subject: 'Test Subject',
+      body: 'Test body content',
+      priority: 'normal',
+      metadata: {},
+      ...overrides,
+    };
+  }
+
+  it('should expose the email channel', () => {
+    expect(adapter.channel).toBe('email');
+  });
+
+  it('should succeed for a valid email recipient', async () => {
+    const result = await adapter.send(makePayload());
+
+    expect(result.success).toBe(true);
+    expect(result.externalId).toBeDefined();
+    expect(result.externalId).toContain('email-notif-0001');
+  });
+
+  it('should fail for an invalid email recipient', async () => {
+    const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));
+
+    expect(result.success).toBe(false);
+    expect(result.error).toContain('Invalid email address');
+  });
+
+  it('should fail for an empty recipient', async () => {
+    const result = await adapter.send(makePayload({ recipient: '' }));
+
+    expect(result.success).toBe(false);
+    expect(result.error).toContain('Invalid email address');
+  });
+
+  it('should return unique external IDs per send', async () => {
+    const result1 = await adapter.send(makePayload({ id: 'notif-0001' }));
+    const result2 = await adapter.send(makePayload({ id: 'notif-0002' }));
+
+    expect(result1.externalId).not.toBe(result2.externalId);
+  });
+});

